INSERT INTO `soal_fahmil` (`id`, `id_kategori`, `soal`, `jawaban`, `status`) VALUES
(208, 16, 'Ketika saya kuliah pada jurusan ini saya tidak belajar bagaimana membuat program dengan bahasa java saja, tapi saya lebih mempelajari bagaimana menyusun algoritma atau logika dalam membuat suatu program, sehingga ketika membuat program dengan bahasa yang lain saya bisa menyesuaikan. Selain itu, saya mengambil keminatan komputasi cerdas yang mempelajari bagaimana membuat sebuah program yang cerdas, hasilnya jika dilihat dari skripsi saya, saya dapat memprediksi nilai tukar uang dimasa depan. Saya menyelesaikan pendidikan sarjana saya 4 tahun dengan nilai IPK 3.63. Alhamdulillah saya sangat bersyukur, ketika kuliah saya juga aktif berorganisasi, mengikuti perlombaan, mengikuti kepanitiaan, membuat jurnal dan bekerja di lab / bersama dosen. 1', 'Ketika saya kuliah pada jurusan ini saya tidak belajar bagaimana membuat program dengan bahasa java saja, tapi saya lebih mempelajari bagaimana menyusun algoritma atau logika dalam membuat suatu program, sehingga ketika membuat program dengan bahasa yang lain saya bisa menyesuaikan. Selain itu, saya mengambil keminatan komputasi cerdas yang mempelajari bagaimana membuat sebuah program yang cerdas, hasilnya jika dilihat dari skripsi saya, saya dapat memprediksi nilai tukar uang dimasa depan. Saya menyelesaikan pendidikan sarjana saya 4 tahun dengan nilai IPK 3.63. Alhamdulillah saya sangat bersyukur, ketika kuliah saya juga aktif berorganisasi, mengikuti perlombaan, mengikuti kepanitiaan, membuat jurnal dan bekerja di lab / bersama dosen. 2', 0),
