(731, 4, 'Sebutkan definisi Hadiah!', 'Hadiah ialah memberikan sesuatu kepada orang lain, dengan tidak mengharapkan apa-apa kecuali untuk memuliakan orang yang diberi hadiah atau menghormatinya', 0),
(732, 4, 'Melakukan dengan sengaja/sadar suatu perbuatan tertentu karena mengikuti perintah Allah agar mendapat Ridho-Nya. Di sebut apa?', 'Niat', 0),
(733, 4, 'Sebutkan Hadis Nabi SAW. tentang niat!', 'ÃÂ¥Ãâ Ãâ¦ÃÂ§ ÃÂ§ÃâÃÂ£ÃÂ¹Ãâ¦ÃÂ§Ãâ ÃÂ¨ÃÂ§ÃâÃâ ÃÅ ÃÂ§ÃÂª  (ÃÂ§ÃâÃÂ¨ÃÂ®ÃÂ§ÃÂ±Ãâ° ÃËÃâ¦ÃÂ³ÃâÃâ¦', 0),
(734, 4, 'Ada berapa tempatkah ayat-ayat sajadah di dalam Al-Qur an?', '15 tempat', 0),
(735, 4, 'Apa arti Sujud Syukur?', 'Sujud Syukur adalah melakukan sujud dikarena berterima kasih atas segala ni mat atau terhindar dari segala bahaya', 0),
(736, 4, 'Apakah pengertian sholat jama ?', 'Sholat jama  adalah menggabungkan dua sholat fardu dalam satu waktu. Yang boleh di jama  itu hanya sholat zuhur dengan ashar dan sholat isya dengan maghrib', 0),
(737, 5, 'Huruf apakah yang keluar dari Aqshallisan ?', 'Qof dan Kaf (  Ãâ   ÃÆ )  ', 0),
(738, 5, 'Huruf apakah yang keluar dari Wasthullisan ?', 'Jim,Syin dan Ya ( ÃÂ¬   ÃÂ´  ÃÅ  )', 0),
(739, 5, 'Huruf apakah yang keluar dari hasil kerjasama antara tepi lidah dan geraham atas ?', 'Huruf Dlod ( ÃÂ¶)', 0),
(740, 5, 'Dari manakah tempat Makhraj huruf  TA (   ÃÂª    )  Dal (   ÃÂ¯    ) dan Tho (  ÃÂ·  ) ?', 'Dari ujung lidah kerjasama dengan pangkal dua gigi seri bagian atas.', 0),
(741, 5, 'Sebutkan huruf-huruf yang bersifat Shofir ?', 'Zay   ( ÃÂ²  ) Sin (  ÃÂ³  ) dan Shod (   ÃÂµ  ).', 0),
(742, 5, 'Darimanakah makhraj huruf Ba,Mim,Wau dan Fa ?', 'Asy-syafatain (kedua bibir ).', 0),
(743, 5, 'Apa yang disebut dengan huruf Al-Janbiyah, sebutkan hurufnya !', 'Huruf yang keluar dari tepi lidah,hurufnya satu :Dhad ( ÃÂ¶  ).', 0),
(744, 5, 'Apa yang disebut dengan Dzalqiyah ?', 'Ujung lidah ( huruf-huruf yang keluar dari ujung lidah )', 0),
(745, 5, 'Apa yang dimaksud dengan Nath iyyah ?', 'Huruf-huruf yang keluar dari kulit ujung langit-langit.', 0),
(746, 5, 'Apa yang dimaksud dengan Lahawiyah ,dan sebutkan huruf-hurufnya ?', 'Huruf yang keluar dari pangkal lidah, hurufnya ada dua : Qaf dan Kaf( Ãâ ÃÆ  )', 0),
(747, 5, 'Apa yang disebut dengan huruf Al-Litsawiyah, dan sebutkan huruf-hurufnya ?', 'Huruf Al-Litsawiyah adalah huruf yang keluar dari gusi depan, hurufnya ada 3: Zha, Tsa dan Dzal ( ÃÂ² ÃÂ« ÃÂ° ).', 0),
(748, 5, 'Dimanakah tempat keluar (makhraj) huruf Ha (   ÃÂ­   ) dan Kha (   ÃÂ®    ) ?', 'Makhraj huruf Ha di tengah tenggorokan (wasath al halq), dan makhraj huruf Kha di ujung tenggorokan  (adna al halq).', 0),
(749, 5, 'Di manakah tempat keluar (makhraj) mad dan hamzah ?', 'Mad keluar dari rongga mulut (al-jawf), dan hamzah keluar dari pangkal tenggorokan (aqsha al halq).', 0),
(750, 5, 'Jelaskan perbedaan antara makhraj huruf Fa  ) ÃÂ  ) dan Qof ( Ãâ ) ?', 'Makhraj huruf Fa (   ÃÂ   ) pada ujung dua gigi depan atas  dengan bagian tengah bibir bawah, sedang makhraj huruf Qaf (   Ãâ   ) pada pangkal lidah sebelah dalam melekat pada langit-langit.', 0);
INSERT INTO `soal_fahmil` (`id`, `id_kategori`, `soal`, `jawaban`, `status`) VALUES
(751, 5, 'Jelaskan perbedaan antara makhraj huruf ra (ÃÂ± ) dan Zay (  ÃÂ²  ) ?', 'Makhraj huruf Ra (  ÃÂ±    ) pada ujung lidah melekat pada gusi (antara Lam dan Nun), sedang makhraj huruf Zay (   ÃÂ²   ) pada ujung lidah dengan rongga antara gigi atas dan bawah,lebih dekat ke gigi atas.', 0),
(752, 5, 'Apa yang disebut huruf Adz-Dzalqiyah, sebutkan huruf-hurufnya ?', 'Huruf Adz-Dzalqiyah adalah huruf yang keluar dari ujung lidah, hurufnya ada 3 : Lam,Nun,Ra.', 0),
(753, 5, 'Apa yang disebut huruf Asy-Syajariyah, sebutkan huruf-hurufnya ?', 'Huruf Asy-Syajariyah adalah huruf yang keluar dari tengah lidah, hurufnya ada 3: Jim,Syin,Ya.', 0),
(754, 5, 'Ditinjau dari segi tertahan dan keluarnya napas, huruf hijaiyah terbagi menjadi berapa ?   sebutkan !', 'Terbagi 2, yaitu Hams (nafas keluar) dan Jahr (nafas tertahan).', 0),
(755, 5, 'Ditinjau dari segi apa huruf hijaiyah terbagi menjadi idzlaq dan ishmat ?', 'Dari segi kelancaran dan kelambanannya keluar dari ujung lidah dan bibir.', 0),
(756, 5, 'Jelaskan perbedaan antara makhraj huruf Shad (   ÃÂµ    ) dan Dhad (    ÃÂ¶   ) !', 'Makhraj huruf shad (  ÃÂµ    ) pada ujung lidah dengan rongga antara gigi atas dan bawah dekat gigi atas, sedang makhraj huruf dhad (  ÃÂ¶   ) pada salah satu tepi lidah (ihda haffatay al-lisan) dengan geraham atas.', 0),
(757, 5, 'Jelaskan perbedaan antara makhraj huruf Tha (   ÃÂ·    ) dan Zha  ) ÃÂ¸  ) !', 'Makhraj huruf Tha (   ÃÂ·   ) pada ujung lidah dengan pangkal dua gigi depan atas,     sedang makhraj huruf Zha (  ÃÂ¸   ) pada ujung lidah dengan ujung dua gigi depan atas.', 0),
(758, 5, 'Dalam hukum nun mati atau tanwin, apa yang disebut dengan Ikhfa aqrab, dan bagaimana cara membacanya ?', 'Ikhfa aqrab yaitu bila nun sukun atau tanwin bertemu dengan huruf ta,dal,tha ( ÃÂª   ÃÂ·   ÃÂ¯ )  Cara membacanya, ikhfanya lebih lama dari ghunnahnya.', 0),
(759, 5, 'Apa yang disebut dengan Mad Lazim Kilmy Mutsaqqal dan berikan contohnya ?', 'Mad Lazim Kilmy Mutsaqqal yaitu apabila ada mad thabi i bertemu dengan tasydid dalam satu kata contoh :ÃÂ§ÃâÃÂ­ÃÂ§ÃâÃÂ©', 0),
(760, 5, 'Apa yang dimaksud dengan huruf Jawfiyyah ?', 'Huruf-huruf yang keluar dari rongga mulut dan tenggorokan.', 0),
(761, 5, 'Apa yang dimaksud dengan huruf Litsawiyah ?', 'Gigi Geraham.', 0),
(762, 5, 'Apa yang dimaksud dengan Ushuluts Tsanaya dalam Ilmu Tajwid ?', 'Pangkal gigi seri.', 0),
(763, 5, 'Apa yang dimaksud dengan Al-Isti la ?', 'Terangkat/naiknya lidah kelangit-langit atas ketika huruf-huruf diucapkan.', 0),
(764, 5, 'Sebutkan huruf-huruf yang memiliki sifat Al-Ithbaq ?', 'Shad,Dhad,Tha dan Zha (   ÃÂµ  ÃÂ¶  ÃÂ·  ÃÂ¸   ).', 0),
(765, 5, 'Kapan dua huruf hijaiyah dikatakan Mutaqaribain ?', 'Ketika keduanya berdekatan makhroj dan sifatnya, makhrajnya saja atau sifatnya saja yang satu sukun yang lainnya hidup, contoh ta dan dzal.', 0),
(766, 5, 'Apa yang dimaksud dengan Waqaf Ikhtibari ?', 'Yaitu waqaf ujian, menguji pembaca bagaimana cara berhenti pada satu kata.', 0),
(767, 5, 'Apa yang dimaksud dengan Waqaf idhtirori ?', 'Yaitu waqaf karena terpaksa, seperti disebabkan lupa, nafas pendekdan lain-lain.', 0),
(768, 5, 'Sebutkan sifat-sifat huruf Ba ( ÃÂ¨ ) !', 'Ada enam (6) : Jahr, Syiddah, Qalqalah, Istifal, Infitah, Idzlaq.', 0),
(769, 5, 'Ada berapa sifat huruf Ta ( ÃÂª ) ? Sebutkan !', 'Ada lima ( 5 ) : Syiddah, , Istifal, , Infitah,  Hams, dan Ishmat.', 0),
(770, 5, 'Sebutkan sifat-sifat huruf Qaf (   Ãâ   ) !', 'Jahr, Syiddah, Isti la, Qalqalah, Infitah, dan Ishmat.', 0),
(771, 5, 'Sebutkan sifat-sifat huruf Mim (   Ãâ¦   ) !', 'Jahr, Tawassuth, Istifal, Infitah, Ghunnah dan Idzlaq.', 0),
(772, 5, 'Sebutkan sifat-sifat huruf Nun ( Ãâ  ) !', 'Jahr, Tawassuth, Istifal, Infitah, Ghunnah dan Idzlaq.', 0),
(773, 5, 'Sebutkan sifat-sifat huruf Dal (   ÃÂ¯   ) !', 'Jahr, Syiddah, Qalqalah, Istifal,Infitah, dan Ishmat.', 0),
(774, 5, 'Sebutkan sifat-sifat huruf Jim (  ÃÂ¬    ) !', 'Jahr, Syiddah, Qalqalah, Istifal,Infitah, dan Ishmat.', 0),
(775, 5, 'Sebutkan sifat-sifat huruf Zay (   ÃÂ²   ) !', 'Jahr, Shofir, Rakhawah, Istifal,Infitah, dan Ishmat.', 0),
(776, 5, 'Sebutkan sifat-sifat huruf Ha Besar (  Ã¯Â»Â«    ) !', 'Hams, Rakhawah, Istifal, Infitah, Ishmat dan Khafa.', 0),
(777, 5, 'Apa yang dimaksud dengan sifat huruf Tawassuth ?', 'Sifat huruf yang berada diantara sifat syiddah dan rakhawah.', 0),
(778, 5, 'Apa yang dimaksud dengan Rakhawah ?', 'Mengalirnya suara bersama huruf ketika huruf diucapkan, karena lemahnya sandaran huruf pada makhraj.', 0),
(779, 5, 'Apa yang dimaksud dengan Syiddah ?', 'Tertahannya suara ketika huruf diucapkan karena kuatnya sandaran pada makhraj.', 0),
(780, 5, 'Apa yang dimaksud dengan sifat huruf Hams?', 'Keluarnya nafas bersama huruf karena lemahnya sandaran huruf pada makhraj.', 0),
(781, 5, 'Apa yang disebut dengan mad Farqi ?, dan berikan contoh !', 'Mad Farqi adalah apabila ada hamzah istifham (  ÃÂ£  ) bertemu dengan lam ta rif (  ÃÂ§Ãâ   ) baik diidghamkan atau sukun contoh :', 0),
(782, 5, 'Apa yang disebut dengan Mad Lazim Harfy Mukhaffaf ?, dan berikan contoh !', 'Mad Lazim Harfy Mukhaffaf yaitu apabila ada huruf fawatihussuwar yang asal ejaannya tiga huruf di dalamnya ada mad thabi i yang bertemu sukun. Contoh :  ÃÂ§ÃâÃÂ±', 0),
(783, 5, 'Apa yang dimaksud dengan Al-Lahn dalam ilmu Tajwid ?', 'Al-Lahn artinya salah menyimpang dari yang benar (baik salah jali maupun khafi).', 0),
(784, 5, 'Huruf-huruf hijaiyyah dari segi pengucapan pada pokoknya terbagi dua, tafkhim / taghlizh dan tarqiq. Sebutkan pengertian tafkhim dan tarqiq!', 'Tafkhim / taghlizh adalah mengucapkan huruf dengan cara tebal, memenuhi mulut disebabkan terhalangi oleh huruf yang diucapkan.  Sedangkan tarqiq adalah mengucapkan huruf dengan cara tipis, tidak memenuhi mulut disebabkan tidak terhalangi oleh huruf yang diucapkan.', 0),
(785, 5, 'Sebutkan 5 huruf dari huruf-huruf yang pada aslinya dibaca tipis!', 'ÃÂ« ÃÂ¨ ÃÂª ÃÂ¹ ÃÂ² Ãâ¦ Ãâ  ÃÅ  ÃÂ¬ ÃË ÃÂ¯ ÃÂ­ ÃÂ± ÃÂ Ãâ¡ ÃÂ¡ ÃÂ° ÃÂ³ Ãâ ÃÂ´ ÃÆ ÃÂ§ (ÃÂ«ÃÂ¨ÃÂª ÃÂ¹ÃÂ² Ãâ¦Ãâ  ÃÅ ÃÂ¬ÃËÃÂ¯ ÃÂ­ÃÂ±ÃÂÃâ¡ ÃÂ§ÃÂ° ÃÂ³Ãâ ÃÂ´ÃÆÃÂ§)', 0),
(786, 5, 'Sebutkan definisi ilmu tajwid secara etimologi dan terminologi !', 'Tajwid secara etimologi adalah memperindah. Sedangkan secara terminologi tajwid adalah Ilmu yang memberikan pengertian tentang hak-hak huruf dari sifat huruf dan mustahaqqul huruf.', 0),
(787, 5, 'Jelaskan tentang tathrib (ÃÂªÃÂ·ÃÂ±ÃÅ ÃÂ¨) dan hukumnya  dalam ilmu tajwid!', 'Tathrib adalah melagukan al-Qur an sehingga membaca panjang (mad) tak pada tempatnya atau memanjangkan yang seharusnya dibaca pendek karena disesuaikan dengan lagunya. Hukumnya haram bagi yang membaca al-Qur an dengan cara tathrib. ', 0),
(788, 5, 'Jelaskan tentang tarji  (ÃÂªÃÂ±ÃÂ¬ÃÅ ÃÂ¹) dan hukumnya  dalam ilmu tajwid!', 'Tarji  adalah membaca al-Qur an dengan tempo naik turun; rendah kemudian tinggi, lantas merendah  dan meninggi lagi dalam satu bacaan panjang (mad).  Hukumnya haram bagi yang membaca al-Qur an dengan cara tarji .', 0),
(789, 5, 'Jelaskan tentang tar id (ÃÂªÃÂ±ÃÂ¹ÃÅ ÃÂ¯) dan hukumnya  dalam ilmu tajwid!', 'Tar id adalah mengalunkan suara yang terlalu bergetar layaknya orang yang kedinginan atau kesakitan. Hukumnya haram bagi yang membaca al-Qur an dengan cara tar id.', 0),
(790, 5, 'Termasuk bacaan yang terlarang adalah bacaan syadz. Jelaskan apa yang dimaksud syadz!', 'Syadz adalah yakni bacaan yang menyalahi bacaan masyhur yang telah disepakati ke-mutawattir-annya (qira at sab ah).', 0),
(791, 5, 'Apa yang dimaksud hak huruf? Jelaskan beserta contohnya!', 'Hak huruf adalah Makhraj huruf dan sifat-sifatnya yang lazimah (tetap) seperti jahr, hams, syiddah, tawassuth, rakhawah dsb. ', 0),
(792, 5, 'Apa yang dimaksud mustahak huruf? Jelaskan beserta contohnya!', 'Mustahak huruf adalah hukum-hukum baru yang ada pada huruf seperti sifat bacaan tebal, tipis, mad, hukum nun mati dan tanwin dsb. ', 0),
(793, 5, 'Apa yang dimaksud al-Lahn al-Jaliy (ÃÂ§ÃâÃâÃÂ­Ãâ  ÃÂ§ÃâÃÂ¬ÃâÃÅ ) dalam ilmu tajwid? Jelaskan beserta contohnya!', 'al-Lahn al-Jaliy ÃÂ§ÃâÃâÃÂ­Ãâ  ÃÂ§ÃâÃÂ¬ÃâÃÅ \nYaitu  kesalahan yang nyata pada lafazh sehingga kesalahan tersebut dapat diketahui oleh para ulama Qira at, maupun orang Islam pada umumnya. Misalnya:\n1.  Mengganti huruf dengan huruf lain (ÃÂ¥ÃÂ¨ÃÂ¯ÃÂ§Ãâ ÃÂ­ÃÂ±ÃÂ ÃÂ¨ÃÂ­ÃÂ±ÃÂ), \n2. Mengganti harakat dengan harakat lain (ÃÂ¥ÃÂ¨ÃÂ¯ÃÂ§Ãâ ÃÂ­ÃÂ±ÃÆÃÂ© ÃÂ¨ÃÂ­ÃÂ±ÃÆÃÂ©), \n3. Mengganti sukun dengan harakat (ÃÂ¥ÃÂ¨ÃÂ¯ÃÂ§Ãâ ÃÂ³ÃÆÃâ  ÃÂ¨ÃÂ­ÃÂ±ÃÆÃÂ©\n4. Atau menambah atau mengurangi huruf (ÃÂ²ÃÅ ÃÂ§ÃÂ¯ÃÂ© ÃÂ£ÃË Ãâ ÃâÃÂµÃÂ§Ãâ  ÃÂ§ÃâÃÂ­ÃÂ±ÃËÃÂ). \n5. Mengubah makna atau tidak, hukumnya haram.', 0),
(794, 5, 'Apa yang dimaksud al-Lahn al-Khafi (ÃÂ§ÃâÃâÃÂ­Ãâ  ÃÂ§ÃâÃÂ®ÃÂÃÅ ) dalam ilmu tajwid? Jelaskan beserta contohnya!', 'al-Lahn al-Khafiy (ÃÂ§ÃâÃâÃÂ­Ãâ  ÃÂ§ÃâÃÂ®ÃÂÃÅ ) \nadalah kesalahan yang tersembunyi pada lafazh. Kesalahan ini hanya dapat diketahui oleh para ulama Qira at atau kalangan tertentu yang mendalami Qira at. Misalnya menggetarkan (takrÃÂ®r) huruf  ra (ÃÂ±)  secara berlebihan atau sebaliknya.\n', 0),
(795, 5, 'Menurut a immah al-qurra  al-muta akhirin bahwa ketentuan wajib dalam membaca Al-Qur an terdapat dua macam; wajib syar i dan wajib shana i. sebutkan definisi dan contoh kedua wajib tersebut!', 'Wajib syar i adalah ketentuan bila dikerjakan dapat pahala dan bila ditnggalkan maka berdosa, seperti menjaga huruf dari perubahan struktur (mabna)-nya dan dapat merusak makna.\nSedangkan wajib shana i adalah ketentuan bila dilakukan maka terpuji dan bila ditinggalkan maka tercela dan harus diberi teguran atau sanksi yang pantas, seperti hukum idgham,ikhfa,iqlab, tafkhim, tarqiq dan lain-lain.\n', 0),
(796, 5, 'Sebutkan definisi wajib syar i dan wajib shana i menurut a immah al-qurra  al-mutaqaddimin beserta contohnya!', 'Wajib syar i adalah ketentuan yang telah disepakati oleh para qurra  seperti hukum idgham, izhhar, ikhfa, iqlab, mad dan qashr yang tidak ada perbedaan di kalangan para qurra .\nSedangkan wajib shana i adalah ketentuan yang berbeda-beda diantara para qurra , seperti perbedaan dalam ilmu qira ah.\n', 0),
(797, 5, 'Jelaskan tentang hukum meninggalkan wajib syar i menurut a immah al-qurra  al-mutaqaddimin !', 'Hukumnya fasiq dan berdosa besar karena terdapat nash perintahnya yaitu Hadis Nabi SAW dari Hudzaifah ibn al-Yaman yang diriwayatkan oleh ath-Thabrani dan al-Baihaqi:\nÃâÃÂ§Ãâ ÃÂ±ÃÂ³ÃËÃâ ÃÂ§ÃâÃâÃâ¡ ÃÂµÃâÃâ° ÃÂ§ÃâÃâÃâ¡ ÃÂ¹ÃâÃÅ Ãâ¡ ÃË ÃÂ³ÃâÃâ¦ \nÃÂ§ÃâÃâÃÂ±ÃÅ½ÃÂ¡ÃÂÃËÃÂ§ ÃÂ§ÃâÃâÃâÃÂÃÂ±ÃâÃÂ¢Ãâ ÃÅ½ ÃÂ¨ÃÂÃâÃÂÃÂ­ÃÂÃËÃâ ÃÂ ÃÂ§ÃâÃâÃÂ¹ÃÅ½ÃÂ±ÃÅ½ÃÂ¨ÃÂ ÃËÃÅ½ÃÂ£ÃÅ½ÃÂµÃâÃËÃÅ½ÃÂ§ÃÂªÃÂÃâ¡ÃÅ½ÃÂ§ÃÅ ÃËÃÅ½ÃÂ¥ÃÂÃÅ ÃâÃÅ½ÃÂ§ÃÆÃÂÃâ¦Ãâ ÃËÃÅ½ÃâÃÂÃÂ­ÃÂÃËÃâ ÃÅ½ ÃÂ£ÃÅ½Ãâ¡ÃâÃâÃÂ ÃÂ§ÃâÃâÃÂÃÂÃÂ³ÃâÃâÃÂ ÃËÃÅ½ÃÂ£ÃÅ½Ãâ¡ÃâÃâÃÂ ÃÂ§ÃâÃâÃÆÃÂÃÂªÃÅ½ÃÂ§ÃÂ¨ÃÅ½ÃÅ ÃâÃâ ÃÂÃÅ ÃÂÃÅ½ÃÂ¥ÃÂÃâ ÃâÃÅ½Ãâ¡ÃÂ ÃÂ³ÃÅ½ÃÅ ÃÅ½ÃÂ¬ÃÂÃÅ ÃÂ¡ÃÂ Ãâ¦ÃÂÃâ Ãâ ÃÂ¨ÃÅ½ÃÂ¹ÃâÃÂ¯ÃÂÃÅ  ÃâÃÅ½ÃËÃâÃâ¦ÃÅ ÃÅ ÃÂÃÂ±ÃÅ½ÃÂ¬ÃâÃÂÃÂ¹ÃÂÃËÃâ ÃÅ½ ÃÂ¨ÃÂÃÂ§ÃâÃâÃâÃÂÃÂ±ÃâÃÂ¢Ãâ ÃÂ ÃÂªÃÅ½ÃÂ±ÃâÃÂ¬ÃÂÃÅ ÃÂ¹ÃÅ½ ÃÂ§ÃâÃâÃÂºÃÂÃâ ÃÅ½ÃÂ§ÃÂ¡ÃÂ ÃËÃÅ½ÃÂ§ÃâÃÂ±ÃâÃÅ½Ãâ¡ÃÅ½ÃÂ¨ÃÅ½ÃÂ§Ãâ ÃÂÃÅ ÃâÃÅ½ÃÂ©ÃÂ ÃËÃÅ½ÃÂ§ÃâÃâ ÃâÃÅ½ÃËÃâÃÂ­ÃÂ ÃâÃÅ½ÃÂ§ ÃÅ ÃÂÃÂ¬ÃÅ½ÃÂ§ÃËÃÂÃÂ²ÃÂ ÃÂ­ÃÅ½Ãâ ÃÅ½ÃÂ§ÃÂ¬ÃÂÃÂ±ÃÅ½Ãâ¡ÃÂÃâ¦ÃâÃÅ Ãâ¦ÃÅ½ÃÂÃâÃÂªÃÂÃËÃâ ÃÅ½ÃÂ©ÃÅ ÃâÃÂÃâÃÂÃËÃÂ¨ÃÂÃâ¡ÃÂÃâ¦Ãâ ÃËÃÅ½ÃâÃÂÃâÃÂÃËÃÂ¨ÃÂ Ãâ¦ÃÅ½Ãâ Ãâ ÃÅ ÃÂÃÂ¹ÃâÃÂ¬ÃÂÃÂ¨ÃÂÃâ¡ÃÂÃâ¦Ãâ ÃÂ´ÃÅ½ÃÂ£ÃâÃâ ÃÂÃâ¡ÃÂÃâ¦Ãâ\n', 0),
(798, 5, 'Jelaskan tentang hukum meninggalkan wajib shana i menurut a immah al-qurra  al-mutaqaddimin !', 'Hukumnya tidak fasiq dan tidak berdosa seperti perbedaan qira ah pada  surat at-Taubah ayat 100: ÃËÃÂ£ÃÂ¹ÃÂ¯ ÃâÃâ¡Ãâ¦ ÃÂ¬Ãâ ÃÂ§ÃÂª ÃÂªÃÂ¬ÃÂ±ÃÅ  ÃÂªÃÂ­ÃÂªÃâ¡ÃÂ§ ÃÂ§ÃâÃÂ£Ãâ Ãâ¡ÃÂ§ÃÂ±\nImam ibn Katsir membaca dengan tambahan min (Ãâ¦Ãâ ) setelah lafazh ÃÂªÃÂ¬ÃÂ±Ãâ° , Sedangkan Imam-imam yang lain membaca tanpa min.\n', 0),
(799, 5, 'Sebutkan tempat atau masalah yang berlaku hukum wajib shana i menurut a immah al-qurra  al-mutaqaddimin !', '1. Dalam masalah khilafiyah qira ah.\n2. Dalam masalah waqaf, karena tidak wajib berhenti pada kalimat tertentu  dan tidak haram pula berhenti pada kalimat secara  ainiyah atau lafzhiyahnya kecuali kalimat tersebut dibuat tidak jelas tujuan artinya (berbuat wahm), jika berbuat wahm dan meyakini pada ketidak-jelasan tujuan artinya maka hukum kafir.\n3. Dalam mempelajari qira ah kepada guru yang ahli, teliti dan tidak memperlakukan kesalahan bacaan (lahn). Sedangkan bagi orang yang melanggar hukum yang telah disepakati para qurra  atau bukan orang yang berbahasa arab maka ia harus belajar kepada orang yang ahli dalam bidang qira ah (masyayikh). Jika tidak maka ia berdosa menurut consensus para qurra .\n', 0),
(800, 5, 'Berapakah jumlah huruf-huruf ashliyah menurut pendapat yang masyhur!', 'Huruf-huruf ashliyah berjumlah 29 huruf, yaitu huruf-huruf hija iyah', 0),
(801, 5, 'Sebutkan 3 huruf dari huruf-huruf far iyah menurut pendapat yang masyhur!', '1. Hamzah yang dibaca tashil\n2. Alif yang dibaca imalah\n3. Shad yang dibaca isymam\n4. Ya yang dibaca isymam\n5. Alif yang dibaca tebal (tafkhim/taghlizh)', 0),
(802, 5, 'Sebutkan definisi huruf ashliyah dan huruf far iyah!', 'Huruf ashliyah adalah huruf yang keluar dari satu makhraj tertentu, sedangkan huruf far iyah ialah huruf yang keluar dari dua makhraj atau tidak jelas antara dua huruf.', 0),
(803, 5, 'Harakat atau tanda baca hidup terbagi dua; harakat ashliyah dan harakat far iyah. Sebutkan kedua harakat tersebut!', 'Harakat ashliyah ialah fathah, dhammah, dan kasrah. Sedangkan harakat far iyah ialah harakat imalah dan harakat isymam.', 0),
(804, 5, 'Makharij al-huruf menurut pendapat mayoritas dan masyhur berjumlah 17 makhraj. Namun ada yang berpendapat 16 dan 14. Siapakah imam yang berpendapat jumlah makhraj 16 dan 14?', 'Yang berpendapat 16 makhraj diantaranya adalah imam Sibawaih dan imam Syathibi. Sedangkan yang berpendapat 14 makhraj diantaranya adalah pendapat imam Quthrub, imam al-Jarami, imam ibn Kisan dan imam ibn Ziyad al-Farra ', 0),
(805, 5, 'Sebutkan faedah atau kegunaan mengetahui sifatt-sifat huruf!', '1. Dapat membedakan huruf-huruf yang bersamaan keluar dari satu makhraj.\n2. Dapat mengetahui huruf-huruf yang bisa diidghamkan dan tidak bisa diidghamkan.\n3. Dapat memperbaiki pengucapan huruf-huruf yang berbeda makhraj.', 0),
(806, 5, 'Sifat huruf terbagi dua; sifat lazimah dan sifat  aridhah. Sebutkan definisi kedua sifat tersebut beserta contohnya!', 'Sifat lazimah ialah sifat yang tetap melekat pada huruf dan tidak berubah seperti 17 sifat huruf.\nSedangkan sifat  aridhah ialah sifat yang sering berubah-rubah tidak tetap melekat pada suatu huruf, seperti sifat tarqiq, tafkhim, ghunnah, ikhfa dan lain-lain.\n', 0),
(807, 5, 'Sebutkan sifat-sifat huruf yang termasuk ke dalam sifat qawiyah!', '1. Jahr                        5. Ishmat                             9.   Shafir\n2. Syiddah                 6.  Qalqalah                       10.  Takrir\n3. Isti la                      7.  Inhiraf                           11.  Istithalah\n4. Ithbaq                    8.  Tafasyi', 0),
(808, 5, 'Sebutkan sifat-sifat huruf yang termasuk ke dalam sifat dha ifah!', '1. Hams                                                4.  Infitah\n2. Rakhawah dan tawassuth                   5.  Idzlaq\n3. Istifal                                                6.  Lin', 0),
(809, 5, 'Sebutkan perbedaan sifat huruf ÃÂ¹ÃÅ Ãâ  dan ÃÂ­ÃÂ§ÃÂ¡ !', 'Huruf ÃÂ¹ÃÅ Ãâ   bersifat jahr dan tawassuth. Sedangkan huruf ÃÂ­ÃÂ§ÃÂ¡ bersifat hams dan rakhawah.', 0),
(810, 5, 'Sebutkan perbedaan sifat huruf ÃÂºÃÅ Ãâ  dan ÃÂ®ÃÂ§ÃÂ¡ !', 'Huruf ÃÂºÃÅ Ãâ  bersifat jahr. Sedangkan huruf Ãâ¡ÃÂ§ÃÂ¡  bersifat hams.', 0),
(811, 5, 'Sebutkan perbedaan sifat huruf ÃÂ¬ÃÅ Ãâ¦ dan ÃÂ´ÃÅ Ãâ  !', 'Huruf ÃÂ¬ÃÅ Ãâ¦ bersifat jahr dan syiddah. Sedangkan huruf ÃÂ´ÃÅ Ãâ  bersifat hams, rakhawah dan tafasyi.', 0),
(812, 5, 'Sebutkan sifat persamaan dan perbedaan pada huruf ta (ÃÂª), dal (ÃÂ¯), dan tha (ÃÂ·)!', 'Sifat persamaan pada huruf ta (ÃÂª), dal (ÃÂ¯), dan tha (ÃÂ·) adalah syiddah. Sedangkan sifat perbedaannya ialah huruf tha memiliki sifat isti la dan ithbaq, sedangkan huruf dal berlawanan dengan kedua sifat tersebut. Adapun ta memiliki sifat hams.', 0),
(813, 5, 'Sebutkan sifat persamaan dan perbedaan pada huruf tsa (ÃÂ«), dzal  (ÃÂ°) dan zha (ÃÂ¸)!', 'Persamaan sifat pada huruf tsa (ÃÂ«), dzal  (ÃÂ°) dan zha (ÃÂ¸) ialah rakhawah. Perbedaan sifat antara ketiga huruf tersebut ialah huruf zha (ÃÂ¸) isti la dan ithbaq. Huruf dzal  (ÃÂ°) memiliki sifat istifal dan infitah. Sedangkan huruf tsa (ÃÂ«) memiliki sifat hams.', 0),
(814, 5, 'Sebutkan sifat persamaan dan perbedaan pada huruf sin (ÃÂ³), shad  (ÃÂµ) dan zai (ÃÂ²)!', 'Persamaan sifat huruf sin (ÃÂ³), shad  (ÃÂµ) dan zai (ÃÂ²) ialah rakhawah dan shafir. Perbedaan sifat ketiga huruf tersebut ialah huruf shad  (ÃÂµ) memiliki sifat ithbaq dan isti la. Sedangkan huruf sin (ÃÂ³) zai (ÃÂ²) memiliki lawanan kedua sifat tersebut dan hams. Adapun zai (ÃÂ²) memiliki lawanan kedua sifat tersebut dan jahr.', 0),
(815, 5, 'Sebutkan huruf-huruf yang termasuk ke dalam aqwa al-huruf dalam sifat-sifatnya!', 'Tha (ÃÂ·), dhad (ÃÂ¶), zha (ÃÂ¸) dan qaf (Ãâ).', 0),
(816, 5, 'Sebutkan huruf-huruf yang termasuk ke dalam adh af al-huruf dalam sifat-sifatnya!', 'Tsa (ÃÂ«), ha (ÃÂ­), nun (Ãâ ) mim (Ãâ¦), fa(ÃÂ) dan ha (ÃÂ¾).', 0),
(817, 5, 'Jelaskan alasan idgham bighunnah ketika tanwin atau nun sakin bertemu dengan wau dan ya!', 'Tanwin atau nun sakin diidghamkan pada wau atau ya karena nun dengan waw dan ya tersebut memiliki kesamaan sifat yaitu Infitah, istifalah, jahr serta Mad dan Liennya memiliki kemiripan dengan ghunnahnya nun.', 0),
(818, 5, 'Jelaskan alasan idgham bila ghunnah ketika tanwin atau nun sakin bertemu dengan huruf lam dan huruf ra!', 'Sebab dilakukannya Idgham bilaghunnah adalah makhrajnya nun dan karena huruf idgham bilaghunnah berada pada makhraj yang sama yaitu di ujung lidah dengan gusi di atasnya sehingga mereka diidghamkan', 0),
(819, 5, 'Apa yang dimaksud dengan idgham tam dari segi praktik pengucapan dalam konteks tajanus, taqarub dan tamatsul dan berikan contohnya!', 'Idgham Taam : Idgham yang bila huruf yang diidghamkan meng-hilang seutuhnya di dalam mudgham fiih seperti ÃÂ§ÃÂ° ÃÂ¸ÃâÃâ¦ÃËÃÂ§', 0),
(820, 5, 'Apa yang dimaksud dengan idgham naqish dari segi praktik pengucapan dalam konteks tajanus, taqarub dan tamatsul dan berikan contohnya!', 'Idgham Naqish adalah Idgham yang bila huruf yang diidghamkan tidak menghilang seutuhnya di dalam mudghamun fiih namun masih tampak dengan sifatnya seperti    :    Ãâ¦Ãâ  ÃÅ ÃÂ¹Ãâ¦Ãâ   danÃÂ§ÃâÃâ¦ Ãâ ÃÂ®ÃâÃâÃÆÃâ¦   ', 0),
(821, 5, 'Sebutkan tiga (3) perkara yang menghalangi terjadinya idgham pada dua huruf yang sama!', '1. Huruf pertama ( Mudgham) memiliki tanwin seperti ÃÂ³Ãâ¦ÃÅ ÃÂ¹ ÃÂ¹ÃâÃÅ Ãâ¦ .\n2. Huruf pertama ( Mudgham) memiliki tasydid seperti  ÃÂÃÂªÃâ¦ Ãâ¦ÃÅ ÃâÃÂ§ÃÂª ÃÂ±ÃÂ¨Ãâ¡.\n3. Huruf pertama ( Mudgham) merupakan zhamir seperti  ÃÆÃâ ÃÂª ÃÂªÃÂ±ÃÂ§ÃÂ¨ÃÂ§\n', 0),
(822, 5, 'Apa yang dimaksud dengan idgham syamsiyah?', 'idgham syamsiyah adalah idgham yang terjadi pada alif-lam yang disebut lam ta rif bertemu dengan salah satu dari 14 huruf syamsiyah. Adapun huruf syamsiyah yaitu huruf yang ada pada permulaan kata yang terkumpul pada kalimat\nÃÂªÃÂ¨ ÃÂ«Ãâ¦ ÃÂ¯ÃÂ¹ ÃÂ°Ãâ ÃÂ¨ÃÂ§ ÃÂ±Ãâ¦Ãâ° ÃÂ²ÃÂ¯ ÃÂ³Ãâ¦ÃÂ¹ÃÂ©  Ã¯ÆË  ÃÂ´Ãâ¦ ÃÂµÃÂ¯ÃÂ± ÃÂ¶ÃÅ ÃÂ ÃÂ·ÃÂ§ÃÂ¨ ÃÂ¸Ãâ  ÃâÃâ¡ Ãâ ÃÂ¹Ãâ¦\n', 0),
(823, 5, 'Apa yang dimaksud dengan izhhar qamariyah?', 'Izhhar yang terjadi pada lam ta rif bertemu dengan salah satu dari 14 huruf qamariyah, dan huruf-huruf qamariyah terkumpul pada pada kalimat:\nÃÂ§ÃÂ¨ÃÂº ÃÂ­ÃÂ¬ÃÆ ÃËÃÂ®ÃÂ ÃÂ¹ÃâÃÅ Ãâ¦Ãâ¡\n', 0),
(824, 5, 'Apa yang dimaksud dengan qalqalah secara etimologi dan terminologi?', 'Qalqalah menurut arti bahasa berarti menggerakkan dan getar sedangkan menurut arti istilah adalah menggoncangkan makhraj sehingga terdengar pantulan suara yang lebih kuat.', 0),
(825, 5, 'Kapan ha kinayah dibaca pendek?', 'Apabila huruf sebelum dhamir mufrad muzakkar ghaib itu sakin kecuali pada kalimat\nÃÂÃÅ Ãâ¡ Ãâ¦Ãâ¡ÃÂ§Ãâ ÃÂ§\n', 0),
(826, 5, 'Apa yang dimaksud dengan ha saktah?', 'Ha saktah adalah ha zaidah atau tambahan yang didatangkan pada akhir kata dengan tujuan menjaga harakat akhir sebuah kata.', 0),
(827, 5, 'Sebutkan dua tempat yang disepakati oleh a immah al-qurra yang ditambah ha saktah!', 'Yaitu pada kata-kata berikut: ÃâÃâ¦ ÃÅ ÃÂªÃÂ³Ãâ Ãâ¡ , ÃÂ§ÃâÃÂªÃÂ¯Ãâ¡ , ÃÆÃÂªÃÂ§ÃÂ¨ÃÅ Ãâ¡  , ÃÂ­ÃÂ³ÃÂ§ÃÂ¨ÃÅ Ãâ¡  ,  Ãâ¦ÃÂ§ÃâÃÅ Ãâ¡  ,  ÃÂ³ÃâÃÂ·ÃÂ§Ãâ ÃÅ Ãâ¡  , Ãâ¦ÃÂ§Ãâ¡ÃÅ Ãâ¡', 0),
(828, 5, 'Apa yang dimaksud dengan waqaf (ÃËÃâÃÂ) dan qatha  (ÃâÃÂ·ÃÂ¹) dalam istilah ilmu tajwid?', 'Waqaf adalah menghentikan bacaan atau suara sejenak pada akhir suku kata untuk mengambil nafas dengan maksud melanjutkan bacaan pada ayat berikutnya.\nSedangkan Qatha  adalah mengakhiri bacaan Al-Qur an dengan me-motong bacaan sama sekali. Dan apabila hendak membuka bacaan kembali sesudah melakukan qatha , disunahkan membaca isti adzah lagi.\n', 0),
(829, 6, 'Sebutkan definisi ayat makiyyah dan ayat madaniyyah secara terminology menurut pendapat yang masyhur!', 'Makiyyah adalah ayat-ayat al-Qur an yang diturunkan sebelum Nabi Muhammad hijrah ke Madinah dan Madaniyyah adalah ayat-ayat al-Qur an yang diturunkan sesudah Nabi Muhammad hijrah ke Madinah.', 0),
(830, 6, 'Sebutkan dua ciri dari ciri-ciri ayat makiyyah dan madaniyyah menurut pendapat yang masyhur!', '1.ÃÂ ÃÂ ÃÂ ÃÂ  Ayat makiyyah diawali dengan    ÃÅ ÃÂ§ÃÅ Ãâ¡ÃÂ§ ÃÂ§ÃâÃâ ÃÂ§ÃÂ³ dan  ÃÅ ÃÂ§ ÃÂ¨Ãâ Ãâ° ÃÂ¢ÃÂ¯Ãâ¦   sedangkan ayat madaniyyah diawali dengan  ÃÅ ÃÂ§ÃÅ Ãâ¡ÃÂ§ ÃÂ§ÃâÃÂ°ÃÅ Ãâ  ÃÂ¢Ãâ¦Ãâ ÃËÃÂ§\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Isi kandungan ayat makiyyah tentang keyakinan dan keimanan serta kisah umat terdahulu sedangkan isi ayat madaniyyah tentang ketentuan hukum wajib dan sunnah.\n3.ÃÂ ÃÂ ÃÂ ÃÂ  Ayat makiyyah merupakan  jawaban terhadap orang-orang kafir sedangkan ayat madaniyyah jawaban terhadap ahlul kitab dan kaum munafik.\n', 0),
(831, 6, 'Terjadi perbedaan pendapat di kalangan mufassirin tentang ayat yang pertama kali turun. Sebutkan ayat yang pertama kali turun (nomor dan nama surat serta ayatnya saja) menurut pendapat yang shahih!', 'Ayat al-Qur an yang pertama kali turun kepada Nabi Muhammad adalah QS. [96] al- Alaq ayat 1-5 ketika beliau bertahannuts di goa Hiro.', 0),
(832, 6, 'Sebutkan ayat al-Qur an yang pertama kali turun (nomor dan nama surat serta ayatnya saja) tentang perintah perang menurut pendapat yang masyhur!', 'QS. [22] al-Hajj: 39.\nÃÂ£ÃÂÃÂ°ÃÂÃâ ÃÅ½ ÃâÃÂÃâÃâÃÅ½ÃÂ°ÃÂÃÅ Ãâ ÃÅ½ ÃÅ ÃÂÃâÃÅ½ÃÂ§ÃÂªÃÅ½ÃâÃÂÃËÃâ ÃÅ½ ÃÂ¨ÃÂÃÂ£ÃÅ½Ãâ ÃâÃÅ½Ãâ¡ÃÂÃâ¦Ãâ ÃÂ¸ÃÂÃâÃÂÃâ¦ÃÂÃËÃÂ§ ÃËÃÅ½ÃÂ¥ÃÂÃâ ÃâÃÅ½ ÃÂ§ÃâÃâÃâÃÅ½Ãâ¡ÃÅ½ ÃÂ¹ÃÅ½ÃâÃÅ½Ãâ° Ãâ ÃÅ½ÃÂµÃâÃÂ±ÃÂÃâ¡ÃÂÃâ¦Ãâ ÃâÃÅ½ÃâÃÅ½ÃÂ¯ÃÂÃÅ ÃÂ±ÃÅ', 0),
(833, 6, 'Sebutkan ayat al-Qur an yang pertama kali turun (nomor dan nama surat serta ayatnya saja) tentang keharaman khamr secara mutlak!', 'QS. [5] al-Ma idah: 90.\nÃÅ ÃÅ½ÃÂ§ ÃÂ£ÃÅ½ÃÅ ÃâÃÂÃâ¡ÃÅ½ÃÂ§ ÃÂ§ÃâÃâÃÅ½ÃÂ°ÃÂÃÅ Ãâ ÃÅ½ ÃÂ¢Ãâ¦ÃÅ½Ãâ ÃÂÃËÃÂ§Ãâ ÃÂ¥ÃÂÃâ ÃâÃÅ½Ãâ¦ÃÅ½ÃÂ§ ÃÂ§ÃâÃâÃÂ®ÃÅ½Ãâ¦ÃâÃÂ±ÃÂ ÃËÃÅ½ÃÂ§ÃâÃâÃâ¦ÃÅ½ÃÅ ÃâÃÂ³ÃÂÃÂ±ÃÂ ÃËÃÅ½ÃÂ§ÃâÃâÃÂ£ÃÅ½Ãâ ÃÂµÃÅ½ÃÂ§ÃÂ¨ÃÂ ÃËÃÅ½ÃÂ§ÃâÃâÃÂ£ÃÅ½ÃÂ²ÃâÃâÃÂ§ÃÅ½Ãâ¦ÃÂ ÃÂ±ÃÂÃÂ¬ÃâÃÂ³ÃÅ Ãâ¦ÃÂÃâÃâ Ãâ ÃÂ¹ÃÅ½Ãâ¦ÃÅ½ÃâÃÂ ÃÂ§ÃâÃÂ´ÃâÃÅ½ÃÅ ÃâÃÂ·ÃÅ½ÃÂ§Ãâ ÃÂ ÃÂÃÅ½ÃÂ§ÃÂ¬ÃâÃÂªÃÅ½Ãâ ÃÂÃÂ¨ÃÂÃËÃâ¡ÃÂ ÃâÃÅ½ÃÂ¹ÃÅ½ÃâÃâÃÅ½ÃÆÃÂÃâ¦Ãâ ÃÂªÃÂÃÂÃâÃâÃÂÃÂ­ÃÂÃËÃâ ÃÅ½', 0),
(834, 6, 'Sebutkan ayat al-Qur an yang pertama kali turun (nomor dan nama surat serta ayatnya saja) tentang makanan yang diharamkan!', 'QS. [6] al-An am : 145.\nÃâÃÂÃâ ÃâÃÂ§ÃâÃÅ½ ÃÂ£ÃÅ½ÃÂ¬ÃÂÃÂ¯ÃÂ ÃÂÃÂÃÅ  Ãâ¦ÃÅ½ÃÂ§ ÃÂ£ÃÂÃËÃâÃÂ­ÃÂÃÅ ÃÅ½ ÃÂ¥ÃÂÃâÃÅ½ÃÅ ÃâÃÅ½ Ãâ¦ÃÂÃÂ­ÃÅ½ÃÂ±ÃâÃÅ½Ãâ¦Ãâ¹ÃÂ§ ÃÂ¹ÃÅ½ÃâÃÅ½Ãâ° ÃÂ·ÃÅ½ÃÂ§ÃÂ¹ÃÂÃâ¦ÃÂ ÃÅ ÃÅ½ÃÂ·ÃâÃÂ¹ÃÅ½Ãâ¦ÃÂÃâ¡ÃÂ ÃÂ¥ÃÂÃâÃÂ§ÃâÃÅ½ ÃÂ£ÃÅ½Ãâ  ÃÅ ÃÅ½ÃÆÃÂÃËÃâ ÃÅ½ Ãâ¦ÃÅ½ÃÅ ÃâÃÂªÃÅ½ÃÂ©Ãâ¹ ÃÂ£ÃÅ½ÃËÃâ ÃÂ¯ÃÅ½Ãâ¦Ãâ¹ÃÂ§ Ãâ¦ÃâÃÅ½ÃÂ³ÃâÃÂÃÂÃËÃÂ­Ãâ¹ÃÂ§ ÃÂ£ÃÅ½ÃËÃâ ÃâÃÅ½ÃÂ­ÃâÃâ¦ÃÅ½ ÃÂ®ÃÂÃâ ÃâÃâ¬ÃÂ²ÃÂÃÅ ÃÂ±ÃÂ ÃÂÃÅ½ÃÂ¥ÃÂÃâ ÃâÃÅ½Ãâ¡ÃÂ ÃÂ±ÃÂÃÂ¬ÃâÃÂ³ÃÅ ÃÂ£ÃÅ½ÃËÃâ ÃÂÃÂÃÂ³ÃâÃâÃâ¹ÃÂ§ ÃÂ£ÃÂÃâ¡ÃÂÃâÃâÃÅ½ ÃâÃÂÃÂºÃÅ½ÃÅ ÃâÃÂ±ÃÂ ÃÂ§ÃâÃâÃâÃâ¡ÃÂ ÃÂ¨ÃÂÃâ¡ÃÂ ÃÂÃÅ½Ãâ¦ÃÅ½Ãâ ÃÂ ÃÂ§ÃÂ¶ÃâÃÂ·ÃÂÃÂ±ÃâÃÅ½ ÃÂºÃÅ½ÃÅ ÃâÃÂ±ÃÅ½ ÃÂ¨ÃÅ½ÃÂ§ÃÂºÃÂ ÃËÃÅ½ÃâÃÂ§ÃÅ½ ÃÂ¹ÃÅ½ÃÂ§ÃÂ¯ÃÂ ÃÂÃÅ½ÃÂ¥ÃÂÃâ ÃâÃÅ½ ÃÂ±ÃÅ½ÃÂ¨ÃâÃÅ½ÃÆÃÅ½ ÃÂºÃÅ½ÃÂÃÂÃËÃÂ±ÃÅ ÃÂ±ÃâÃÅ½ÃÂ­ÃÂÃÅ Ãâ¦ÃÅ', 0),
(835, 6, 'Sebutkan ayat al-Qur an yang pertama kali turun (nomor dan nama surat serta ayatnya saja) yang terdapat di dalamnya sujud tilawah!', 'QS. [53]: 62.\nÃÂÃÅ½ÃÂ§ÃÂ³ÃâÃÂ¬ÃÂÃÂ¯ÃÂÃËÃÂ§ ÃâÃÂÃâÃâÃÅ½Ãâ¡ÃÂ ÃËÃÅ½ÃÂ§ÃÂ¹ÃâÃÂ¨ÃÂÃÂ¯ÃÂÃËÃÂ§', 0),
(836, 6, 'Sebutkan ayat al-Qur an yang terakhir turun (nomor dan nama surat serta ayatnya saja) menurut pendapat yang rajih!', 'QS. [2] al-Baqarah : 281.\nÃËÃÅ½ÃÂ§ÃÂªÃâÃÅ½ÃâÃÂÃËÃÂ§Ãâ ÃÅ ÃÅ½ÃËÃâÃâ¦Ãâ¹ÃÂ§ ÃÂªÃÂÃÂ±ÃâÃÂ¬ÃÅ½ÃÂ¹ÃÂÃËÃâ ÃÅ½ ÃÂÃÂÃÅ Ãâ¡ÃÂ ÃÂ¥ÃÂÃâÃÅ½Ãâ° ÃÂ§ÃâÃâÃâÃâ¡ÃÂ ÃÂ«ÃÂÃâ¦ÃâÃÅ½ ÃÂªÃÂÃËÃÅ½ÃÂÃâÃÅ½Ãâ° ÃÆÃÂÃâÃâÃÂ Ãâ ÃÅ½ÃÂÃâÃÂ³ÃÂ Ãâ¦ÃâÃÅ½ÃÂ§ ÃÆÃÅ½ÃÂ³ÃÅ½ÃÂ¨ÃÅ½ÃÂªÃâ ÃËÃÅ½Ãâ¡ÃÂÃâ¦Ãâ ÃâÃÂ§ÃÅ½ ÃÅ ÃÂÃÂ¸ÃâÃâÃÅ½Ãâ¦ÃÂÃËÃâ ÃÅ½', 0),
(837, 6, 'Pada masa pengumpulan al-Qur an oleh panitia yang dibentuk oleh khalifah Abu Bakar ash-Shidiq terdapat catatan dua ayat terakhir surat Bara ah yang diajukan kepada panitia pengumpulan al-Qur an. Siapakah orang yang mengajukan dua ayat terakhir surat Bara ah tersebut?', 'Khuzaimah al-Anshari', 0),
(838, 6, 'Apa yang dimaksud kaedah tafsir  Ã¢â¬ÅÃÂ§ÃâÃÂ¹ÃÂ¨ÃÂ±ÃÂ© ÃÂ¨ÃÂ¹Ãâ¦ÃËÃâ¦ ÃÂ§ÃâÃâÃÂÃÂ¸ ÃâÃÂ§ ÃÂ¨ÃÂ®ÃÂµÃËÃÂµ ÃÂ§ÃâÃÂ³ÃÂ¨ÃÂ¨Ã¢â¬Â ?', 'Pengambilan hukum didasarkan pada keumuman lafazh bukan didasarkan pada kekhususan sebab turunnya al-Qur an.', 0),
(839, 6, 'Apa yang dimaksud dengan kaedah tafsir \n\nÃ¢â¬ÅÃâÃÂÃÂ¸ ÃâÃâ¡ ÃÂ¹Ãâ¦ÃËÃâ¦ ÃÂ¥Ãâ¦ÃÂ§ ÃÂ¢ÃÅ ÃÂ© Ãâ ÃÂ²ÃâÃÂª ÃÂÃÅ  Ãâ¦ÃÂ¹ÃÅ Ãâ  ÃËÃâÃÂ§ ÃÂ¹Ãâ¦ÃËÃâ¦ ÃâÃâÃÂÃÂ¸Ãâ¡ÃÂ§ ÃÂÃÂ¥Ãâ Ãâ¡ÃÂ§ ÃÂªÃâÃÂµÃÂ± ÃÂ¹ÃâÃÅ Ãâ¡ ÃâÃÂ·ÃÂ¹ÃÂ§Ã¢â¬Â?', 'Lafazh yang memiliki arti umum seperti ayat yang diturunkan kepada orang tertentu sedangkan secara lafzhiyah tidak termasuk shighat umum maka pasti ayat tersebut berlaku khusus hanya kepada orang tersebut.', 0),
(840, 6, 'Sebutkan dua hikmah dari beberapa hikmah mengetahui latar belakang turunnya al-Qur an!', '1.ÃÂ ÃÂ ÃÂ ÃÂ  Dapat mengetahui penyebab disyariatkannya hukum tertentu\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Dapat membantu memahami makna ayat dan menghilangkan kemusykilannya\n3.ÃÂ ÃÂ ÃÂ ÃÂ  Dapat mengetahui kekhususan hukum pada orang tertentu\n4.ÃÂ ÃÂ ÃÂ ÃÂ  Dapat mengetahui lafazh umum sedangkan hukumnya takhshish.', 0),
(841, 6, 'Apa yang dimaksud kaedah tafsir berikut ini:\n\nÃ¢â¬ÅÃËÃâ¦Ãâ  ÃÂ§ÃâÃÂ£ÃÂ¯ÃâÃÂ© ÃÂ¹ÃâÃâ° ÃÂ§ÃÂ¹ÃÂªÃÂ¨ÃÂ§ÃÂ± ÃÂ¹Ãâ¦ÃËÃâ¦ ÃÂ§ÃâÃâÃÂÃÂ¸ ÃÂ§ÃÂ­ÃÂªÃÂ¬ÃÂ§ÃÂ¬ ÃÂ§ÃâÃÂµÃÂ­ÃÂ§ÃÂ¨ÃÂ© ÃËÃÂºÃÅ ÃÂ±Ãâ¡Ãâ¦ ÃÂÃÅ  ÃËÃâÃÂ§ÃÂ¦ÃÂ¹ ÃÂ¨ÃÂ¹Ãâ¦ÃËÃâ¦ ÃÂ¢ÃÅ ÃÂ§ÃÂª Ãâ ÃÂ²ÃâÃÂª ÃÂ¹ÃâÃâ° ÃÂ£ÃÂ³ÃÂ¨ÃÂ§ÃÂ¨ ÃÂ®ÃÂ§ÃÂµÃÂ©Ã¢â¬Â ?', 'Maksudnya adalah ayat al-Qur an yang memiliki kekhususan sabab an-nuzul lalu dijadikan hujjah oleh para sahabat nabi dan orang-orang yang berkompeten dalam menafsirkan al-Qur an didasarkan pada keumuman lafazhnya maka ayat tersebut berlaku umum.', 0),
(842, 6, 'Faedah apakah dalam literature beberapa kitab tafsir al-Qur an, terdapat suatu ayat yang memiliki banyak asabab an-nuzul?', 'Faedah dari keaneka-ragaman asbab an-nuzul itu menunjukkan penafsiran  ayat tersebut bukan penuturan sabab an-nuzul dan tidak bertentangan antara sabab-sabab nuzul tersebut ketika keumuman lafazh dari ayat itu meliputi terhadap peristiwa-peristiwa tersebut.', 0),
(843, 6, 'Bagaimana cara penyelesaian jika diantara kitab tafsir berbeda penuturan sabab an-nuzul suatu ayat?', 'Pendapat mu tamad (pendapat yang dijadikan sebagai pegangan) adalah sabab an-nuzul yang shahih dalam periwayatannya.', 0),
(844, 6, 'Apa faedah dari turunnya beberapa ayat al-Qur an secara berulang-ulang?', 'Faedahnya adalah sebagai peringatan, mau izhah dan menunjukkan keagungan isi kandungannya.', 0),
(845, 6, 'Ayat-ayat al-Qur an ada yang diturunkan dalam satu surat dan ada juga tidak satu surat (terpisah). Contohkan dua surat yang diturunkan tidak dalam satu surat sekaligus?', 'Rata-rata, ayat- ayat al-Qur an diturunkan tidak dalam satu surat sekaligus seperti surat al- Alaq dari ayat 1 Ã¢â¬â 5, surat adh-Dhuha 1-5', 0),
(846, 6, 'Contohkan dua surat al-Qur an yang diturunkan dalam satu surat sekaligus!', 'Al-Fatihah, al-Ikhlash, al-Kautsar, al-Lahab, an-Nashr, al-Mu awwidzatain, al-Bayyinah, al-Mursalat, ash-Shaf, al-An am.', 0),
(847, 6, 'Jelaskan berapa kali al-Qur an diturunkan dari al-Lauh al-Mahfuzh menurut pendapat yang lebih shahih dan masyhur?', 'Dua kali\n1.ÃÂ ÃÂ ÃÂ ÃÂ  Diturunkan secara sekaligus dari al-Lauh al-Mahfuzh ke langit pertama dan di simpan di bait al- Izzah pada malam lailat al-Qadr.\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Dari bait al- Izzah diturunkan kepada nabi Muhammad secara berangsur-angsur selama 20 tahun/ 23 tahun/ 25 tahun (terjadi khilafiyah).', 0),
(848, 6, 'Sebutkan dua hikmah dari beberapa hikmah diturunkannya al-Qur an secara berangsur-angsur!', '1.ÃÂ ÃÂ ÃÂ ÃÂ  Mengukuhkan al-Qur an ke dalam hati nabi Muhammad SAW\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Untuk menghadapi tantangan dan membuat tidak mampu (melumpuhkan) pada penantang al-Qur an.\n3.ÃÂ ÃÂ ÃÂ ÃÂ  Memudahkan dalam menghafal dan memahami al-Qur an.\n4.ÃÂ ÃÂ ÃÂ ÃÂ  Mengatasi persoalan dan tahapan dalam penetapan hukum\n5.ÃÂ ÃÂ ÃÂ ÃÂ  Sebagai petunjuk yang bersifat konklusif, final dan absolut dari Allah Yang Maha Bijaksana', 0),
(849, 6, 'Sebutkan dua faedah dari turunnya al-Qur an secara berangsur-angsur dalam dunia pengajaran dan pendidikan!', '1.ÃÂ ÃÂ ÃÂ ÃÂ  Menjaga standar mentalitas siswa\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Pengembangan kemampuan siswa dalam sisi intelektual, emosional, dan spiritual serta fisik ke arah yang lebih baik menggunakan metode yang benar.', 0),
(850, 6, 'Sebutkan dua cara pengumpulan al-Qur an pada masa nabi Muhammad SAW!', '1.ÃÂ ÃÂ ÃÂ ÃÂ  Dikumpulkan ke dalam dada para sahabat dengan cara menghafalnya (al-Qur an).\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Mengumpulkan para sahabat agar mencatat al-Qur an', 0),
(851, 6, 'Sebutkan panitia pengumpulan al-Qur an pada masa khalifah Abu Bakar ash-Shidiq!', '1.ÃÂ ÃÂ ÃÂ ÃÂ  Zaid ibn ats-Tsabit al-Anshari sebagai ketua\n2.ÃÂ ÃÂ ÃÂ ÃÂ  Abdullah ibn az-Zubair sebagai anggota\n3.ÃÂ ÃÂ ÃÂ ÃÂ  Sa id ibn al- Ash sebagai anggota\n4.ÃÂ ÃÂ ÃÂ ÃÂ   Abd ar-Rahman ibn al-Harits ibn al-Hisyam sebagai anggota', 0),
(852, 6, 'Apa yang melatarbelakangi Umar ibn al-Khaththab mengajukan usulan kepada khalifah Abu Bakar ash-Shidiq agar catatan-catatan al-Qur an dikumpulkan kembali?', 'Wafatnya 70 sahabat penghafal al-Qur an pada perang Yamamah dan dikhawatirkan al-Qur an hilang dengan hilangnya atau meninggalnya para huffazh.', 0),
(853, 6, 'Apa yang dimaksud dengan Ã¢â¬ÅHaqiqahÃ¢â¬Â dalam sumber istilah dan makna bahasa al-Qur an ?', 'Haqiqah adalah kata yang lafadznya digunakan sebagaimanapertama kali dipergunakan dalam konteks kebahasaan.', 0),
(854, 6, 'Apa yang dimakksud dengan Lughawiyyah Wadh iyyah (al-Haqiqah al-Lughawiyyah)?', 'Lughawiyyah Wadh iyyah (al-Haqiqah al-Lughawiyyah) adalah kata yang lafadznyadigunakan untuk menunjukkan makna hakiki berdasarkankonteks penggunaan asal kata tersebut', 0),
(855, 6, 'Apa yang dimaksud dengan Lughawiyyah Manqulah?', 'Lughawiyyah Manqulah adalah kata yang lafadznyadigunakan untuk menunjukkan makna hakiki setelahmengalami transformasi maksud, baik yang dilakukan olehahli bahasa atau pembuat syariat.', 0),
(856, 6, 'Apa yang dimaksud dengan Al-Haqiqah al-Lughawiyyah al- Urfiyyah?', 'Al-Haqiqah al-Lughawiyyah al- Urfiyyah adalahlafadz yang mengalami tranformasi maksud dari maknaasal penggunaannya, kepada makna lain, yang kemudianpopuler dengan makna tersebut, sehingga makna lafadzasalnya ditinggalkan. ', 0),
(857, 6, 'Berikan contoh lafazh yang termasuk ke dalam Al-Haqiqah al-Lughawiyyah al- Urfiyyah!', 'Misalnya lafadz: ad-Dabbah (hewan melata). Asalnya lafadz ini mempunyai konotasi hewan melata di muka bumi, yang meliputi manusia dan hewan. Namun, kemudian digunakan oleh orang Arab dengan konotasi hewan berkaki empat, sehingga makna asalnya ditinggalkan.', 0),
(858, 6, 'Apa yang dimaksud dengan Ã¢â¬ÅAl-Haqiqah al-Lughawiyyah as-Syar iyyahÃ¢â¬Â?', 'Al-Haqiqah al-Lughawiyyah as-Syar iyyah adalah lafadz yang mengalami transformasi maksud dari makna asal penggunaannya kepada makna lain, yang digunakan oleh pembuat syariat atau harus dinyatakan oleh dalil syara .', 0),
(859, 6, 'Berikan contoh lafazh yang termasuk ke dalam Al-Haqiqah al-Lughawiyyah as-Syar iyyah!', 'Misalnya lafadz: shalat, as-shiyam, al-Islam, al-kufr dan lain-lain.', 0),
(860, 6, 'Apa yang dimaksud dengan Ã¢â¬ÅmajazÃ¢â¬Â?', 'Majaz adalah lafadz yang digunakan tidak sesuai dengan asal penggunaannya yang pertama, karena adanya indikasi yang menghalangi dinyatakannya makna yang hakiki.', 0),
(861, 6, 'Dariaspek hubungan antara makna yang digunakan denganmakna yang diletakkan pertama kali, terbagi berapa Majaz itu? Dan sebutkan!', 'Majaz terbagi dua yaitu majaz Isti arah dan majaz Mursal', 0),
(862, 6, 'Apa yang dimaksud dengan Ã¢â¬Åmajaz Isti arahÃ¢â¬Â?', 'Isti arah : Secara harfiah, isti arah berarti meminjam. Disebut demikian, karena pada dasarnya Majaz dalam konteks ini disusun dengan meminjam lafadz asal untuk digunakan dengan maksud baru, karena adanya persamaan (musyabahah) antara masing-masing.', 0),
(863, 6, 'Diantara beberapa cara penerimaan Wahyu yang dialami Nabi Muhammad SAW, ada cara yang dianggp paling cepat. Dengan cara apakah itu?', 'Dengan cara ada tanda suara keras, seperti gemerincing lonceng', 0),
